/* ═══════════════════════════════════════════════════════════════
   js/pdf.js — PDF generation using pdf-lib

   BEFORE USE: paste your two base64 strings below where marked.
   To convert a PDF to base64:
     - Open browser console on any page
     - Run: fetch('your-file.pdf').then(r=>r.arrayBuffer()).then(b=>console.log(btoa(String.fromCharCode(...new Uint8Array(b)))))
     - Or use: https://base64.guru/converter/encode/pdf
═══════════════════════════════════════════════════════════════ */

// ── PSI FORM BASE64 ───────────────────────────────────────────
// Paste the base64 string for psi Concorde big file_compressed.pdf here.
// It will start with: JVBERi0x  (which is %PDF-1 in base64)
const ORIGINAL_PDF_B64 = '';
// ↑ PASTE PSI PDF BASE64 HERE (replace the empty string above)


// ── MEWP INSPECTION FORM BASE64 ──────────────────────────────
// Paste the base64 string for MEWP_PreUse_Inspection_NAMED_v3.pdf here.
const MEWP_PDF_B64 = '';
// ↑ PASTE MEWP PDF BASE64 HERE (replace the empty string above)


// ── DATE HELPER ───────────────────────────────────────────────
function fmtDateWords(isoStr) {
  var months = ['January','February','March','April','May','June',
                'July','August','September','October','November','December'];
  var parts = (isoStr || todayISO()).split('-');
  var m = parseInt(parts[1], 10) - 1;
  var d = parseInt(parts[2], 10);
  var y = parts[0];
  return months[m] + ' ' + d + ' ' + y;
}

// ── BUILD PSI PDF ─────────────────────────────────────────────

async function buildPDF(psi, opts) {
  opts = opts || {};

  if (!ORIGINAL_PDF_B64) {
    toast('⚠ PDF template not loaded — paste base64 into pdf.js');
    return;
  }

  if (typeof PDFLib === 'undefined') {
    toast('⚠ pdf-lib not loaded — check internet connection');
    return;
  }

  try {
    toast('Building PDF…');

    const { PDFDocument, rgb } = PDFLib;

    // 1. Load the PDF from base64
    const pdfBytes  = base64ToUint8Array(ORIGINAL_PDF_B64);
    const pdfDoc    = await PDFDocument.load(pdfBytes, { ignoreEncryption: true });
    const form      = pdfDoc.getForm();
    const pages     = pdfDoc.getPages();
    const page      = pages[0];
    const { height } = page.getSize();

    // 2. Helper: fill text field (silent fail if field missing)
    function sf(fieldName, value) {
      try {
        const field = form.getTextField(fieldName);
        field.setText(value || '');
      } catch(e) {
        // field not found — skip silently
      }
    }

    // 3. Helper: check/uncheck checkbox
    function cb(fieldName, checked) {
      try {
        const field = form.getCheckBox(fieldName);
        if (checked) { field.check(); } else { field.uncheck(); }
      } catch(e) {
        // field not found — skip silently
      }
    }

    // 4. Fill text fields
    sf(PDF_FIELDS.date,        psi.jobDate     || '');
    sf(PDF_FIELDS.time,        psi.jobTime     || '');
    sf(PDF_FIELDS.jobNumber,   psi.jobNumber   || '');
    sf(PDF_FIELDS.taskDesc,    psi.taskDesc    || '');
    sf(PDF_FIELDS.taskLoc,     psi.taskLoc     || '');
    sf(PDF_FIELDS.musterPoint, psi.musterPoint || '');
    sf(PDF_FIELDS.supName,     psi.supName     || psi.approvedBy || '');

    // 5. Fill worker names (up to 4)
    const workers = (psi.workers || []).filter(function(w) { return w.name && w.name.trim(); });
    const workerFields = [PDF_FIELDS.worker1, PDF_FIELDS.worker2, PDF_FIELDS.worker3, PDF_FIELDS.worker4];
    workerFields.forEach(function(fieldName, i) {
      sf(fieldName, workers[i] ? workers[i].name : '');
      // Signature drawn as image after flatten — do not fill text into sig field
    });

    // 6. Fill task_steps, hazard, control — three separate text areas
    // New format: separate string fields; backward compat: old tasks array
    var taskStepText = psi.taskStepsText || '';
    var hazardTxt    = psi.hazardText    || '';
    var controlTxt   = psi.controlText   || '';

    if (!taskStepText && psi.tasks && psi.tasks.length) {
      // Old format fallback
      var activeTasks = psi.tasks.filter(function(r) { return r[0] || r[1] || r[2]; });
      taskStepText = activeTasks.map(function(r) { return r[0] || ''; }).filter(Boolean).join('\n');
      hazardTxt    = activeTasks.map(function(r) { return r[1] || ''; }).filter(Boolean).join('\n');
      controlTxt   = activeTasks.map(function(r) { return r[2] || ''; }).filter(Boolean).join('\n');
    }

    // 6b. Append weather info if present
    // Weather condition line  → appended to hazard field
    // Weather advisory tips   → appended to control field
    if (psi.weather || psi.weatherTemp !== undefined) {
      var wxCondLine = 'YYC Weather: ' + (psi.weather || (psi.weatherTemp + '\u00b0C'));
      hazardTxt = hazardTxt ? hazardTxt + '\n' + wxCondLine : wxCondLine;
    }
    if (psi.weatherAdvisory && psi.weatherAdvisory.length) {
      var wxBlock = 'Weather Precautions:\n' +
        psi.weatherAdvisory.map(function(s) { return '\u2022 ' + s; }).join('\n');
      controlTxt = controlTxt ? controlTxt + '\n\n' + wxBlock : wxBlock;
    }

    sf(PDF_FIELDS.taskSteps, taskStepText);
    sf('hazard',  hazardTxt);
    sf('control', controlTxt);

    // 7. Check hazard checkboxes
    (psi.hazards || []).forEach(function(fieldName) {
      cb(fieldName, true);
    });

    // 8. Check PPE checkboxes
    (psi.ppe || []).forEach(function(label) {
      const item = PPE_ITEMS.find(function(p) { return p.label === label; });
      if (item) cb(item.field, true);
    });

    // 9. Clear all signature + initial text fields so old text doesn't bake in
    ['worker_1_signature','worker_2_signature','worker_3_signature','worker_4_signature','supervisor_signature',
     '1st_b1','1st_b2','1st_b3','1st_b4','lunch1','lunch2','lunch3','lunch4','2n_b1','2n_b2','2n_b3','2n_b4'].forEach(function(f) {
      try { form.getTextField(f).setText(''); } catch(e) {}
    });

    // 10. Flatten the form so signatures draw on top cleanly
    form.flatten();

    // 11. Draw worker signatures as crisp vector lines
    const sigs = psi.sigs || {};
    for (let i = 0; i < Math.min(workers.length, 4); i++) {
      const sig = sigs[i];
      if (!sig || !sig.strokes) continue;
      drawSigLines(page, sig.strokes, SIG_RECTS['worker_' + (i + 1)], rgb);
    }

    // 12. Supervisor signature
    const supStrokes = opts.supStrokes || psi.supSigStrokes;
    if (supStrokes && supStrokes.length) {
      drawSigLines(page, supStrokes, SIG_RECTS.supervisor, rgb);
    }

    // 13. Draw break initials as vector lines
    for (const entry of (psi.initials || [])) {
      if (!entry.breakType || !entry.strokes) continue;
      const rects = BREAK_RECTS[entry.breakType];
      if (!rects) continue;
      const idx = workers.findIndex(function(w) {
        return w.name && w.name.trim().toLowerCase() === (entry.name || '').trim().toLowerCase();
      });
      if (idx < 0 || idx >= 4) continue;
      drawSigLines(page, entry.strokes, rects[idx], rgb);
    }

    // 14. Save and download
    const outBytes = await pdfDoc.save();
    const blob     = new Blob([outBytes], { type: 'application/pdf' });
    const url      = URL.createObjectURL(blob);

    const jobCode = psi.jobCode || 'PSI';
    const dateStr = fmtDateWords(psi.jobDate);
    const desc    = (psi.taskDesc || 'PSI').replace(/\s+/g, '-');
    const shortId = (psi.id || '').slice(0, 5);
    const fname   = dateStr + ' - PSI ' + jobCode + ' ' + desc + (shortId ? ' ' + shortId : '') + '.pdf';

    const a = document.createElement('a');
    a.href     = url;
    a.download = fname;
    document.body.appendChild(a);
    a.click();
    setTimeout(function() { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);

    toast('📄 PDF downloaded!');

  } catch(err) {
    console.error('[buildPDF]', err);
    toast('⚠ PDF error: ' + (err.message || 'unknown'));
  }
}


// ── DRAW SIGNATURE AS VECTOR LINES ON PAGE ────────────────────
// strokes = [{points:[[x,y],...]},...], rect = {x,y,w,h} in pdf-lib bottom-left coords

function drawSigLines(page, strokes, rect, rgb) {
  if (!strokes || !strokes.length) return;

  // Find bounding box of all stroke points
  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
  strokes.forEach(function(s) {
    (s.points || []).forEach(function(p) {
      if (p[0] < minX) minX = p[0];
      if (p[1] < minY) minY = p[1];
      if (p[0] > maxX) maxX = p[0];
      if (p[1] > maxY) maxY = p[1];
    });
  });
  if (!isFinite(minX)) return;

  const srcW = maxX - minX || 1;
  const srcH = maxY - minY || 1;
  const pad  = 1;
  const tw   = rect.w - pad * 2;
  const th   = rect.h - pad * 2;
  const scale = Math.min(tw / srcW, th / srcH);

  // Centre within the rect; flip Y (canvas Y down → PDF Y up)
  const ox = rect.x + pad + (tw - srcW * scale) / 2;
  const oy = rect.y + pad + (th - srcH * scale) / 2;

  strokes.forEach(function(s) {
    const pts = s.points;
    if (!pts || pts.length < 2) return;
    for (let j = 1; j < pts.length; j++) {
      page.drawLine({
        start: { x: ox + (pts[j-1][0] - minX) * scale,
                 y: oy + (srcH - (pts[j-1][1] - minY)) * scale },
        end:   { x: ox + (pts[j][0]   - minX) * scale,
                 y: oy + (srcH - (pts[j][1]   - minY)) * scale },
        thickness: 1.2,
        color:     rgb(0, 0, 0),
        opacity:   1,
      });
    }
  });
}


// ── BUILD MEWP INSPECTION PDF ─────────────────────────────────

async function buildMEWPPDF(unitData, sigStrokes, supStrokes) {
  if (!MEWP_PDF_B64) {
    toast('⚠ MEWP PDF template not loaded — paste base64 into pdf.js');
    return;
  }

  if (typeof PDFLib === 'undefined') {
    toast('⚠ pdf-lib not loaded');
    return;
  }

  try {
    toast('Building MEWP PDF…');

    const { PDFDocument, rgb } = PDFLib;

    const pdfBytes = base64ToUint8Array(MEWP_PDF_B64);
    const pdfDoc   = await PDFDocument.load(pdfBytes, { ignoreEncryption: true });
    const form     = pdfDoc.getForm();
    const pages    = pdfDoc.getPages();
    const page     = pages[0];
    const { height } = page.getSize();

    function sf(fieldName, value) {
      try { form.getTextField(fieldName).setText(value || ''); } catch(e) {}
    }

    // Set a radio group to OK / NO / NA
    function sr(fieldName, value) {
      try { form.getRadioGroup(fieldName).select(value); } catch(e) {}
    }

    // Fill text fields (exact field names from MEWP form)
    sf('Operators name', unitData.operator || '');
    sf('Date',           unitData.date     || '');
    sf('Make',           unitData.make     || '');
    sf('Unit',           unitData.unitNum  || '');
    sf('Meter reading',  unitData.meter    || '');

    // Remarks split into two rows
    const remarks = unitData.remarks || '';
    sf('RemarksRow1', remarks.slice(0, 80));
    sf('RemarksRow2', remarks.slice(80, 200));

    // Fill radio groups — PDF template already has OK pre-selected for most fields.
    // Only explicitly set fields the worker marked NO or NA; leave OK fields alone
    // so the PDF's built-in defaults are preserved exactly.
    const checks = unitData.checks || {};
    LIFT_CHECKS.forEach(function(section) {
      section.items.forEach(function(item) {
        var val = checks[item.field] || 'ok';
        if (val === 'no') { sr(item.field, 'NO'); }
        else if (val === 'na') { sr(item.field, 'NA'); }
        // 'ok' → leave as-is (PDF template default is already OK)
      });
    });

    form.flatten();

    // Operator signature
    if (sigStrokes && sigStrokes.length > 0) {
      drawSigLines(page, sigStrokes, { x: 100, y: 60, w: 200, h: 40 }, rgb);
    }

    // Supervisor signature
    if (supStrokes && supStrokes.length > 0) {
      drawSigLines(page, supStrokes, { x: 350, y: 60, w: 200, h: 40 }, rgb);
    }

    // Supervisor name text
    if (unitData.supName) sf('Supervisors name', unitData.supName);

    const outBytes = await pdfDoc.save();
    const blob     = new Blob([outBytes], { type: 'application/pdf' });
    const url      = URL.createObjectURL(blob);

    const dateStr = fmtDateWords(unitData.date);
    const unitStr = (unitData.unitNum || 'unit').replace(/\s+/g, '-');
    const fname   = dateStr + ' - MEWP ' + unitStr + '.pdf';

    const a = document.createElement('a');
    a.href     = url;
    a.download = fname;
    document.body.appendChild(a);
    a.click();
    setTimeout(function() { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);

    toast('📄 MEWP PDF downloaded!');

  } catch(err) {
    console.error('[buildMEWPPDF]', err);
    toast('⚠ MEWP PDF error: ' + (err.message || 'unknown'));
  }
}


// ── BASE64 → Uint8Array ───────────────────────────────────────

function base64ToUint8Array(base64) {
  // Strip data URL prefix if present
  const clean = base64.replace(/^data:[^;]+;base64,/, '');
  const binary = atob(clean);
  const bytes  = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}
